// MARK: - Stripe Payment Setup

class PaymentViewController: UIViewController {

    @IBOutlet weak var cardNumberTextField: UITextField!
    @IBOutlet weak var expiryMonthTextField: UITextField!
    @IBOutlet weak var expiryYearTextField: UITextField!
    @IBOutlet weak var cvcTextField: UITextField!

    override func viewDidLoad() {
        super.viewDidLoad()

        // Set up Stripe payment form
        let paymentForm = STPPaymentCardForm()
        paymentForm.cardNumber = cardNumberTextField.text ?? ""
        paymentForm.expMonth = Int(expiryMonthTextField.text ?? "") ?? 0
        paymentForm.expYear = Int(expiryYearTextField.text ?? "") ?? 0
        paymentForm.cvc = cvcTextField.text ?? ""

        // Create a payment method
        let paymentMethodParams = STPPaymentMethodCardParams()
        paymentMethodParams.card = paymentForm

        // Create a payment intent
        let paymentIntentParams = STPPaymentIntentParams()
        paymentIntentParams.paymentMethodParameters = paymentMethodParams

        // Process the payment
        Stripe.shared().processPayment(paymentIntentParams) { result in
            switch result {
            case .success(let payment):
                print("Payment successful: \(payment)")
            case .failure(let error):
                print("Error processing payment: \(error)")
            }
        }
    }
}